import sys

def main():
    H, W = map(int, sys.stdin.readline().split())
    grid = [list(sys.stdin.readline().strip()) for _ in range(H)]

    # Find the rectangle boundaries
    a, b, c, d = 0, 0, 0, 0

    # Find top boundary (a)
    for i in range(H):
        if '#' in grid[i]:
            a = i
            break

    # Find bottom boundary (b)
    for i in range(H-1, -1, -1):
        if '#' in grid[i]:
            b = i
            break

    # Find left boundary (c)
    for j in range(W):
        if any(grid[i][j] == '#' for i in range(a, b+1)):
            c = j
            break

    # Find right boundary (d)
    for j in range(W-1, -1, -1):
        if any(grid[i][j] == '#' for i in range(a, b+1)):
            d = j
            break

    # Find the missing cookie
    for i in range(a, b+1):
        for j in range(c, d+1):
            if grid[i][j] == '.':
                print(i+1, j+1)
                return

if __name__ == "__main__":
    main()
